class Pilha:
    def __init__(self):
        self._itens = []

    def push(self, item):
        self._itens.append(item)

    def pop(self):
        if self.esta_vazia():
            raise ValueError('Pilha vazia')
        return self._itens.pop()

    def peek(self):
        if self.esta_vazia():
            raise ValueError('Pilha vazia')
        return self._itens[-1]

    def esta_vazia(self):
        return len(self._itens) == 0

    def tamanho(self):
        return len(self._itens)

p = Pilha()
p.push(1)
p.push(2)
p.push(3)
print(p.peek())
print(p.pop())
print(p.tamanho())
print(p.esta_vazia())
